CREATE TEMP TABLE demo_files(folder_path text, name text);
INSERT INTO demo_files VALUES ('Compressors/Asset_Register','Asset_Register.xlsx'),('Compressors/Incident_Inspection','ISO_1217_2009_Preview.pdf'),('Compressors/Instructions_And_Manuals','Carlyle_Open_Drive_Compressor_Alignment.pdf'),('Compressors/Instructions_And_Manuals','Dry_Gas_Seal_Centrifugal_Compressors.pdf'),('Compressors/Instructions_And_Manuals','ISO_1217_2009.pdf'),('Compressors/Maintenance','ACEEE_Compressor_Sequencing_Optimization.pdf'),('Compressors/Product_Descriptions and Spare_Parts','ELGi_EG_75_100V_CAGI_Datasheet.pdf'),('Compressors/Product_Descriptions and Spare_Parts','ELGi_EG_90_100_CAGI_Datasheet.pdf'),('Compressors/Product_Descriptions and Spare_Parts','Elliott_BOG_Compressors.pdf'),('Compressors/Product_Descriptions and Spare_Parts','Interpreting_Compressor_Maps.pdf'),('Compressors/Product_Descriptions and Spare_Parts','Kaeser_FSG_500-2_CAGI_Datasheet.pdf'),('Compressors/Product_Descriptions and Spare_Parts','MAN_Energy_Solutions_MOPICO_Compression_Systems.pdf'),('Compressors/Product_Descriptions and Spare_Parts','MAN_Energy_Solutions_Oil_Free_Screw_Compressors.pdf'),('Compressors/SOPs','LANL_Compressor_OM_Criterion.pdf'),('Compressors/Work_Orders','Work_Orders.xlsx');
SELECT COUNT(*) FROM documents d
JOIN document_catalog c ON c.id=d.catalog_id
JOIN demo_files f ON f.name=c.name AND f.folder_path=c.folder_path
WHERE COALESCE(c.metadata->>'asset_domain','')='Compressors' AND d.status<>'chunked';
